const { execSync } = require('child_process');
const cmd = params.command || 'status';
const cwd = params.cwd || '.';
const allowed = ['status', 'log', 'diff', 'branch', 'show', 'remote', 'config'];
if (!allowed.includes(cmd.split(' ')[0])) {
  throw new Error('Command not allowed: ' + cmd);
}
const result = execSync('git ' + cmd, { cwd, encoding: 'utf-8', timeout: 30000 });
return { output: result };
